  ('dietitian-moex-08034', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '最常在脆丸、油麵、魚蝦等食物中檢出的有害性食品添加物是：', '["過氧化氫", "硼砂", "吊白塊", "奶油黃"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08035', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '營養師法中，主管機關所管轄之事務的敘述，何者正確？', '["審核申請書及相關文件後發給營養師證書者為申請者所在地之主管機關", "營養師應向執業所在地直轄市或縣（市）主管機關申請執業登記，領有執業執照始得執業", "營養師應向中央主管機關申請執業登記，領有執業執照始得執業", "營養師接受繼續教育之相關事項之辦法，由各地主管機關訂定之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08036', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '團膳業者應該如何看待顧客抱怨？', '["當多數顧客抱怨同一事件時，才需要重視，其他零星抱怨可視為偶發事件", "醫院團膳屬於非營利事業，無需所謂的客訴處理制度與規定", "找出服務失敗的原因最應該從常客的感受去學習", "對顧客的抱怨處理通常包括道歉、賠償、更新、折扣等方式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08037', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '設計菜單時，須避免下列那些情形？①食材同色系出現  ②同一道菜內食材形狀一致  ③利用盤飾增加', '["同一餐的菜餚中使用相同的烹調方式", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "83e883c42452", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08038', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '教育部為配合學校供應午餐，提出「學校午餐內容及營養素基準」，其中國小4年級到6年級需要熱量 在750大卡，則油脂量建議在多少公克以下？', '["15公克", "25公克", "30公克", "40公克"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "83e883c42452", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
